2925	// Lode-lifecycle fixture — fetched-side base capture against live GAR. Single
2926	// self-contained round-trip: ensconce the busybox base into a fresh rbi_ld
2927	// Lode, divine-enumerate to confirm it appears, divine-inspect to confirm the
2928	// member tags + vouch envelope rode in, banish the whole Lode, then divine-
2929	// enumerate to confirm the registry is restored. Parallel to hallmark-lifecycle
2930	// on the made side. Requires a reliquary yoked on the busybox vessel (same
2931	// precondition hallmark-lifecycle's ordain carries).
2932	fn rbtdrc_lode_lifecycle(dir: &Path) -> rbtdre_Verdict {
2933	    rbtdrc_with_ctx(|ctx| {
2934	        let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
2935	        if !ctx.project_root().join(vessel_dir).is_dir() {
2936	            return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
2937	        }
2938	
2939	        // Step 1: ensconce the busybox base into a fresh Lode.
2940	        let _ = std::fs::write(dir.join("01-ensconce.txt"), "ensconcing busybox base");
2941	        let ensconce = match rbtdri_invoke_global(ctx, RBTDGC_ENSCONCE_BOLE, &[vessel_dir], &[]) {
2942	            Ok(r) if r.exit_code == 0 => r,
2943	            Ok(r) => return rbtdre_Verdict::Fail(format!("ensconce failed (exit {})\n{}", r.exit_code, r.stderr)),
2944	            Err(e) => return rbtdre_Verdict::Fail(format!("ensconce invocation: {}", e)),
2945	        };
2946	        let _ = std::fs::write(dir.join("01-ensconce-stdout.txt"), &ensconce.stdout);
2947	
2948	        // The capture-file root is the Lode touchmark.
2949	        let touchmarks = match rbtdri_read_burv_facts_multi(&ensconce, RBTDRC_FACT_EXT_LODE) {
2950	            Ok(v) => v,
2951	            Err(e) => return rbtdre_Verdict::Fail(format!("read capture-file: {}", e)),
2952	        };
2953	        if touchmarks.len() != 1 {
2954	            return rbtdre_Verdict::Fail(format!("expected exactly 1 capture-file, got {:?}", touchmarks));
2955	        }
2956	        let touchmark = touchmarks[0].clone();
2957	        let _ = std::fs::write(dir.join("02-touchmark.txt"), &touchmark);
2958	
2959	        // Step 2: divine enumerate shows the new Lode.
2960	        let after = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[], &[]) {
2961	            Ok(r) if r.exit_code == 0 => r,
2962	            Ok(r) => return rbtdre_Verdict::Fail(format!("post-ensconce divine failed (exit {})\n{}", r.exit_code, r.stderr)),
2963	            Err(e) => return rbtdre_Verdict::Fail(format!("post-ensconce divine invocation: {}", e)),
2964	        };
2965	        let _ = std::fs::write(dir.join("03-divine-after.txt"), &after.stdout);
2966	        if !after.stdout.contains(&touchmark) {
2967	            return rbtdre_Verdict::Fail(format!(
2968	                "post-ensconce divine missing touchmark {}\nstdout:\n{}",
2969	                touchmark, after.stdout
2970	            ));
2971	        }
2972	
2973	        // Step 3: divine inspect shows the member tags + the vouch envelope.
2974	        let inspect = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[&touchmark], &[]) {
2975	            Ok(r) if r.exit_code == 0 => r,
2976	            Ok(r) => return rbtdre_Verdict::Fail(format!("divine inspect failed (exit {})\n{}", r.exit_code, r.stderr)),
2977	            Err(e) => return rbtdre_Verdict::Fail(format!("divine inspect invocation: {}", e)),
2978	        };
2979	        let _ = std::fs::write(dir.join("04-divine-inspect.txt"), &inspect.stdout);
2980	        for member in &[RBTDRC_LODE_TAG_BOLE, RBTDRC_LODE_TAG_VOUCH, RBTDRC_LODE_TAG_DIGEST_PREFIX] {
2981	            if !inspect.stdout.contains(member) {
2982	                return rbtdre_Verdict::Fail(format!(
2983	                    "divine inspect missing member tag '{}'\nstdout:\n{}",
2984	                    member, inspect.stdout
2985	                ));
2986	            }
2987	        }
2988	
2989	        // Step 4: banish the whole Lode.
2990	        let _ = std::fs::write(dir.join("05-banish.txt"), "banishing");
2991	        match rbtdri_invoke_global(
2992	            ctx,
2993	            RBTDGC_BANISH_LODE,
2994	            &[&touchmark],
2995	            &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)],
