2997	            Ok(r) if r.exit_code == 0 => {}
2998	            Ok(r) => return rbtdre_Verdict::Fail(format!("banish failed (exit {})\n{}", r.exit_code, r.stderr)),
2999	            Err(e) => return rbtdre_Verdict::Fail(format!("banish invocation: {}", e)),
3000	        }
3001	
3002	        // Step 5: divine enumerate no longer shows the Lode — registry restored.
3003	        let final_divine = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[], &[]) {
3004	            Ok(r) if r.exit_code == 0 => r,
3005	            Ok(r) => return rbtdre_Verdict::Fail(format!("final divine failed (exit {})\n{}", r.exit_code, r.stderr)),
3006	            Err(e) => return rbtdre_Verdict::Fail(format!("final divine invocation: {}", e)),
3007	        };
3008	        let _ = std::fs::write(dir.join("06-divine-final.txt"), &final_divine.stdout);
3009	        if final_divine.stdout.contains(&touchmark) {
